checker_dsl:
EXISTS (`taint flow path P`) {
  EXISTS (`source node SRC`) {
    EXISTS (`sink node SNK`) {
      AND {
        (`SRC is an instance of ActiveThreatModelSource`),
        (`SNK is an instance of CommandInjectionSink`),
        (`P is a taint flow path from SRC to SNK`),
        NOT {
          EXISTS (`barrier node B`) {
            AND {
              (`B is an instance of CommandInjectionSanitizer`),
              (`B lies on the taint flow path P`)
            }
          }
        },
        (`execArg is an argument to a command execution method and is represented by the sink node SNK`)
      }
    }
  }
}
